"use strict";(self.webpackChunkdst_api_webdocs=self.webpackChunkdst_api_webdocs||[]).push([[39377],{99949:i=>{i.exports=JSON.parse('{"tag":{"label":"minigame","permalink":"/dst-api-webdocs/docs/tags/minigame","allTagsPath":"/dst-api-webdocs/docs/tags","count":38,"items":[{"id":"game-scripts/prefabs/balatro_machine","title":"Balatro Machine","description":"Hosts the Balatro mini-game session, manages card gameplay state, joker selection, and reward distribution for player interaction.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/balatro_machine"},{"id":"game-scripts/prefabs/balatro_score_utils","title":"Balatro Score Utils","description":"Provides base classes and Joker-specific logic for evaluating poker hands and calculating scores in Balatro minigame rounds.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/balatro_score_utils"},{"id":"game-scripts/prefabs/balatro_util","title":"Balatro Util","description":"Provides shared constants, data encoding utilities, and light animation management for the Balatro minigame system.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/balatro_util"},{"id":"game-scripts/brains/carnival_crowkidbrain","title":"Carnival Crowkidbrain","description":"Controls the AI behavior of the carnival crow kid, managing movement, minigame spectating, decor interaction, campfire watching, and vocalizations based on game state and environment.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/carnival_crowkidbrain"},{"id":"game-scripts/prefabs/carnival_host","title":"Carnival Host","description":"Controls the behavior, interaction, and state of the Carnival Host NPC, including shop management, summoning to plazas, and chatter synchronization.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/carnival_host"},{"id":"game-scripts/brains/carnival_hostbrain","title":"Carnival Hostbrain","description":"Controls the AI behavior of the Carnival Host, managing its interactions with minigames, crowd behavior, and environment navigation.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/carnival_hostbrain"},{"id":"game-scripts/prefabs/carnivalgame_common","title":"Carnivalgame Common","description":"Provides shared functionality for carnival minigame stations, including activation/deactivation lifecycle, scoring, rewards, and camera/focus management.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/carnivalgame_common"},{"id":"game-scripts/prefabs/carnivalgame_feedchicks","title":"Carnivalgame Feedchicks","description":"Manages the feedchicks carnival minigame station, including nest activation, food item spawning, and scoring logic.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/carnivalgame_feedchicks"},{"id":"game-scripts/prefabs/carnivalgame_herding","title":"Carnivalgame Herding","description":"Manages the herding minigame station, including chick spawning, game state transitions, reward generation, and static floor decoration setup.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/carnivalgame_herding"},{"id":"game-scripts/brains/carnivalgame_herding_chick_brain","title":"Carnivalgame Herding Chick Brain","description":"Controls the AI behavior of a herding minigame chick, managing movement via wandering and runaway responses relative to a home location and station markers.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/carnivalgame_herding_chick_brain"},{"id":"game-scripts/prefabs/carnivalgame_memory","title":"Carnivalgame Memory","description":"Manages the memory mini-game station, including card layout, round logic, scoring, and reward spawning for the Carnival event.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/carnivalgame_memory"},{"id":"game-scripts/prefabs/carnivalgame_puckdrop","title":"Carnivalgame Puckdrop","description":"Implements the puck drop carnival minigame station entity, managing gameplay state transitions, door selection timing, and reward spawning.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/carnivalgame_puckdrop"},{"id":"game-scripts/prefabs/carnivalgame_shooting","title":"Carnivalgame Shooting","description":"Implements the shooting minigame station for the Carnival event, managing game state, aiming mechanics, target spawning, and reward distribution for players.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/carnivalgame_shooting"},{"id":"game-scripts/prefabs/carnivalgame_wheelspin","title":"Carnivalgame Wheelspin","description":"Manages the wheel-spin carnival minigame station, including spin logic, scoring, and reward spawning.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/carnivalgame_wheelspin"},{"id":"game-scripts/components/carnivalgameitem","title":"Carnivalgameitem","description":"A placeholder component for items used in carnival minigames.","permalink":"/dst-api-webdocs/docs/game-scripts/components/carnivalgameitem"},{"id":"game-scripts/components/carnivalgameshooter","title":"Carnivalgameshooter","description":"Manages the aiming and shooting mechanics for the carnival shooting mini-game, controlling projectile launch parameters and aim animation.","permalink":"/dst-api-webdocs/docs/game-scripts/components/carnivalgameshooter"},{"id":"game-scripts/map/static_layouts/chess_blocker","title":"Chess Blocker","description":"Defines a static map layout used for the chess minigame world generation, specifying tile backgrounds and object placements.","permalink":"/dst-api-webdocs/docs/game-scripts/map/static_layouts/chess_blocker"},{"id":"game-scripts/components/chessunlocks","title":"Chessunlocks","description":"Manages locking and unlocking of chess piece sketches and associated trinkets in the Don\'t Starve Together chess minigame system.","permalink":"/dst-api-webdocs/docs/game-scripts/components/chessunlocks"},{"id":"game-scripts/prefabs/cozy_bunnyman","title":"Cozy Bunnyman","description":"A playable character with trader, combat, and minigame participation behaviors, primarily used for the YOTR Pillow Fight event.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/cozy_bunnyman"},{"id":"game-scripts/brains/cozy_bunnymanbrain","title":"Cozy Bunnymanbrain","description":"Manages the AI behavior of the Cozy Bunnyman during minigames and normal gameplay, including pillow fights, carrot-spinning contests, and home management.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/cozy_bunnymanbrain"},{"id":"game-scripts/brains/crittersbrain","title":"Crittersbrain","description":"Manages AI behavior for small wildlife entities, handling movement toward owners, avoidance of combat zones, playful interactions with other critters, and observation of active minigames.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/crittersbrain"},{"id":"game-scripts/prefabs/gingerbreadpig","title":"Gingerbreadpig","description":"A mobile, crumb-dropping enemy prefab that chases players and eventually spawns crumb trails for the Gingerbread Hunter mini-game.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/gingerbreadpig"},{"id":"game-scripts/components/hideandseekgame","title":"Hideandseekgame","description":"Manages the Hide and Seek minigame logic, tracking seekers, hiding spots, game state, and rewards.","permalink":"/dst-api-webdocs/docs/game-scripts/components/hideandseekgame"},{"id":"game-scripts/components/inspectaclesparticipant","title":"Inspectaclesparticipant","description":"Manages the state and behavior of the Inspectacles minigame system for an entity, including puzzle generation, game setup, reward granting, and client-server synchronization.","permalink":"/dst-api-webdocs/docs/game-scripts/components/inspectaclesparticipant"},{"id":"game-scripts/brains/kitcoonbrain","title":"Kitcoonbrain","description":"Manages the AI behavior of a kitcoon, handling owner following, combat avoidance, playful interactions with other kitcoons and toys, and minigame observation.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/kitcoonbrain"},{"id":"game-scripts/prefabs/kitcoonden","title":"Kitcoonden","description":"Manages a den structure that hosts hide-and-seek minigames with kitcoons, granting rewards upon successful play.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/kitcoonden"},{"id":"game-scripts/components/lavaarenamobtracker","title":"Lavaarenamobtracker","description":"Tracks entities designated as mobs in the Lava Arena minigame, supporting querying by radius and tags.","permalink":"/dst-api-webdocs/docs/game-scripts/components/lavaarenamobtracker"},{"id":"game-scripts/components/minigame","title":"Minigame","description":"Manages the lifecycle and participant/spectator logic for minigame events in the world.","permalink":"/dst-api-webdocs/docs/game-scripts/components/minigame"},{"id":"game-scripts/components/minigame_participator","title":"Minigame Participator","description":"Tracks and manages an entity\u2019s participation in a minigame, including automatic cleanup, follower disengagement, and timeout handling.","permalink":"/dst-api-webdocs/docs/game-scripts/components/minigame_participator"},{"id":"game-scripts/components/minigame_spectator","title":"Minigame Spectator","description":"Attaches an entity as a passive spectator to a minigame, automatically removing itself when the minigame ends or is deactivated.","permalink":"/dst-api-webdocs/docs/game-scripts/components/minigame_spectator"},{"id":"game-scripts/brains/pigelitebrain","title":"Pigelitebrain","description":"AI brain controlling Pig Elite behavior during minigames, including gold diving, prop pickup, panic responses, and post-match posing.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/pigelitebrain"},{"id":"game-scripts/prefabs/pigking","title":"Pigking","description":"Manages the Pig King\'s trading and wrestling minigame mechanics, including gold/nugget exchange, elite pig participation, area safety validation, and reward distribution.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/pigking"},{"id":"game-scripts/prefabs/pillow_equipment","title":"Pillow equipment","description":"Generates prefabs for body and hand pillows, including associated attack FX, with equipment and weapon behavior tailored for combat and minigames.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/pillow_equipment"},{"id":"game-scripts/prefabs/propsign","title":"Propsign","description":"Implements a breakable, equippable sign prop that functions as a lightweight weapon and interacts with minigame excitement tracking.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/propsign"},{"id":"game-scripts/brains/wobycommon","title":"Wobycommon","description":"Provides shared AI behavior logic and utility functions for Woby, a companion entity in Don\'t Starve Together, including fetching, foraging, ammo retrieval, courier, and minigame watching.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/wobycommon"},{"id":"game-scripts/prefabs/wolfgang","title":"Wolfgang","description":"Implements Wolfgang\u2019s gameplay mechanics including Mightiness system, sanity modifiers based on proximity to enemies/followers, special work gain, and gym-based bell-minigame for gym-based mightiness gain.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/wolfgang"},{"id":"game-scripts/prefabs/yotc_carrat_race_checkpoint","title":"Yotc Carrat Race Checkpoint","description":"Manages the behavior and visual state of a checkpoint used in the Carrat Race minigame, including light toggling, racer detection, and interaction callbacks.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/yotc_carrat_race_checkpoint"},{"id":"game-scripts/prefabs/yotr_fightring","title":"Yotr Fightring","description":"A minigame arena component that facilitates a competitive pillowfight minigame with timed rounds, ring-out mechanics, and prize distribution.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/yotr_fightring"}],"unlisted":false}}')}}]);